const items = $input.all();
const input = items[0].json;
const body = input.body || {};
const resource = input.resource || '';
const action = input.action || '';
const zgwApi = input.zgwApi || '';

let valid = true;
let status = 200;
let detail = '';
let enrichedBody = {...body};

// Rule: Auto-generate identificatie for zaak creates
if (zgwApi === 'zaken' && resource === 'zaken' && action === 'create') {
  if (!body.identificatie || body.identificatie === '') {
    const ts = Date.now().toString(36).toUpperCase();
    const rand = Math.random().toString(36).substring(2, 6).toUpperCase();
    enrichedBody.identificatie = 'ZAAK-' + ts + '-' + rand;
  }
}

return [{ json: { valid, status, detail, enrichedBody } }];
